function extractFunction(source,name){const marker=`function ${name}(`;const start=source.indexOf(marker);assert.notEqual(start,-1,`${name} fehlt`);let i=source.indexOf("{",source.indexOf(")",start)),depth=0,quote="",escaped=false,line=false,block=false;for(;i<source.length;i++){const c=source[i],n=source[i+1];if(line){if(c==="\n")line=false;continue}if(block){if(c==="*"&&n==="/"){block=false;i++}continue}if(quote){if(escaped){escaped=false;continue}if(c==="\\"){escaped=true;continue}if(c===quote)quote="";continue}if(c==="/"&&n==="/"){line=true;i++;continue}if(c==="/"&&n==="*"){block=true;i++;continue}if(c==='"'||c==="'"||c==='`'){quote=c;continue}if(c==="{")depth++;if(c==="}"&&--depth===0)return source.slice(start,i+1);}throw new Error(`${name} unvollständig`);}
function extractElement(source,marker,tag){const at=source.indexOf(marker);assert.notEqual(at,-1,`${marker} fehlt`);const start=source.lastIndexOf(`<${tag}`,at);assert.notEqual(start,-1);const rx=new RegExp(`</?${tag}\\b[^>]*>`,`ig`);rx.lastIndex=start;let depth=0,m;while((m=rx.exec(source))){depth+=m[0][1]==="/"?-1:1;if(!depth)return source.slice(start,rx.lastIndex);}throw new Error(`${marker} unvollständig`);}
for(const item of files){const file=path.join(root,item.path);assert.ok(fs.existsSync(file),`${item.path} fehlt`);const data=fs.readFileSync(file);assert.equal(data.length,item.size,`${item.path} Byte-Länge abweichend`);assert.equal(sha(data),item.sha256,`${item.path} Schutz-Hash abweichend`);}
for(const item of jsRegions){const fragment=extractFunction(read(item.file),item.name);assert.equal(Buffer.byteLength(fragment),item.bytes,`${item.file}::${item.name} Byte-Länge abweichend`);assert.equal(sha(fragment),item.sha256,`${item.file}::${item.name} Schutz-Hash abweichend`);}
const html=read("index.html");for(const item of htmlRegions){const fragment=extractElement(html,item.marker,item.tag);assert.equal(Buffer.byteLength(fragment),item.bytes,`index.html::${item.label} Byte-Länge abweichend`);assert.equal(sha(fragment),item.sha256,`index.html::${item.label} Schutz-Hash abweichend`);}
const css=fs.readFileSync(path.join(root,"assets/app.css"));const prefix=css.subarray(0,291694);assert.equal(sha(prefix),"09f71132f6db4537427f625412a21b6543271a9fc49b43cdec51b37d3774e471","assets/app.css geschützter Präfix abweichend");
